mapper.select:
SELECT A.PROP_CD , A.PROP_NO , A.PROP_NM , A.PROP_FEATURE , A.CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.CAT_CD AND C.CAT_LVL = 0) AS CAT_NM , A.MID_CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.MID_CAT_CD) AS MID_CAT_NM , A.SUB_CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.SUB_CAT_CD) AS SUB_CAT_NM , A.DEAL_TYPE , CASE A.DEAL_TYPE WHEN 'SELL' THEN '매매' WHEN 'JEONSE' THEN '전세' WHEN 'WOLSE' THEN '월세' WHEN 'SHORT' THEN '단기임대' ELSE '' END AS DEAL_TYPE_NM , A.SELL_PRICE , A.DEPOSIT , A.MONTHLY_RENT , A.AREA_EXCLUSIVE , A.ROOM_CNT , A.FLOOR_NO , A.ADDRESS , A.SOLD_YN , CASE A.SOLD_YN WHEN 'Y' THEN '거래완료' ELSE '거래중' END AS SOLD_YN_NM , A.DISPLAY_YN , A.DISPLAY_START , A.DISPLAY_END , A.VIEW_CNT , A.ADMIN_MEMO , A.CRE_USR_CD , (SELECT U.USR_NM FROM TB_USR U WHERE U.USR_CD = A.CRE_USR_CD) AS CRE_USR_NM , DATE_FORMAT(A.CRE_DTM, '%Y-%m-%d') AS CRE_DTM FROM TB_PROPERTY A WHERE A.DEL_YN = 'N' AND A.USE_YN = 'Y'
AND A.CAT_CD = #{catCd}
AND A.MID_CAT_CD = #{midCatCd}
AND A.SUB_CAT_CD = #{subCatCd}
AND A.DEAL_TYPE = #{dealType}
AND A.SOLD_YN = #{soldYn}
AND (A.PROP_NO LIKE CONCAT('%', #{keyword}, '%') OR A.PROP_NM LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY A.CRE_DTM DESC

SELECT COUNT(*)
  FROM TB_PROPERTY A
 WHERE A.DEL_YN = 'N'
   AND A.USE_YN = 'Y'

   AND A.CAT_CD = #{catCd}


   AND A.MID_CAT_CD = #{midCatCd}


   AND A.SUB_CAT_CD = #{subCatCd}


   AND A.DEAL_TYPE = #{dealType}


   AND A.SOLD_YN = #{soldYn}


   AND (A.PROP_NO LIKE CONCAT('%', #{keyword}, '%') OR A.PROP_NM LIKE CONCAT('%', #{keyword}, '%'))

mapper.update:
UPDATE TB_PROPERTY
   SET SOLD_YN    = #{soldYn}
     , UPD_USR_CD = #{ssnUsrCd}
     , UPD_DTM    = NOW()
 WHERE PROP_CD = #{propCd}
   AND DEL_YN = 'N'

mapper.select:
SELECT A.PROP_CD , A.PROP_NM , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.CAT_CD AND C.CAT_LVL = 0) AS CAT_NM , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.MID_CAT_CD) AS MID_CAT_NM , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.SUB_CAT_CD) AS SUB_CAT_NM , CASE A.DEAL_TYPE WHEN 'SELL' THEN '매매' WHEN 'JEONSE' THEN '전세' WHEN 'WOLSE' THEN '월세' WHEN 'SHORT' THEN '단기임대' ELSE '' END AS DEAL_TYPE_NM , A.PROP_FEATURE , A.ADDRESS , A.ADDRESS_DTL , A.BUILDING_NM , A.SELL_PRICE , A.DEPOSIT , A.MONTHLY_RENT , CASE A.LOAN_YN WHEN 'Y' THEN '있음' ELSE '없음' END AS LOAN_YN_NM , A.LOAN_AMOUNT , A.PREMIUM , A.MONTHLY_MGMT , A.AREA_SUPPLY , A.AREA_EXCLUSIVE , A.AREA_LAND , A.AREA_TOTAL , A.ZONE_TYPE , A.ROAD_WIDTH , A.FLOOR_NO , A.FLOOR_TOTAL , A.ROOM_CNT , A.BATH_CNT , A.DIRECTION , CASE A.PARKING_YN WHEN 'Y' THEN '가능' ELSE '불가' END AS PARKING_YN_NM , A.BUILD_DATE , A.ENTRANCE_TYPE , A.HEATING , CASE A.SOLD_YN WHEN 'Y' THEN '거래완료' ELSE '거래중' END AS SOLD_YN_NM , DATE_FORMAT(A.CRE_DTM, '%Y-%m-%d') AS CRE_DTM FROM TB_PROPERTY A WHERE A.DEL_YN = 'N' AND A.USE_YN = 'Y'
AND A.CAT_CD = #{catCd}
AND A.MID_CAT_CD = #{midCatCd}
AND A.SUB_CAT_CD = #{subCatCd}
AND A.DEAL_TYPE = #{dealType}
AND A.SOLD_YN = #{soldYn}
AND (A.PROP_NO LIKE CONCAT('%', #{keyword}, '%') OR A.PROP_NM LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY A.CRE_DTM DESC

mapper.update:
UPDATE TB_PROPERTY_SEQ
   SET LAST_SEQ = LAST_SEQ + 1
 WHERE YEAR_CD = #{yearCd}
